import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import API from '../api/axios';

const CreatePostPage = () => {
  const [title, setTitle] = useState('');
  const [body, setBody] = useState('');
  const [image, setImage] = useState(null);
  const [preview, setPreview] = useState(null); // Added preview state
  const [error, setError] = useState('');

  const [titleFocus, setTitleFocus] = useState(false);
  const [bodyFocus, setBodyFocus] = useState(false);
  const [btnHover, setBtnHover] = useState(false);
  const [btnActive, setBtnActive] = useState(false);

  // 👇 Force re-render on theme change
  const [themeTrigger, setThemeTrigger] = useState(false);

  const { user } = useAuth();
  const navigate = useNavigate();

  /* ================= THEME LISTENER ================= */
  useEffect(() => {
    const handleThemeChange = () => setThemeTrigger(prev => !prev);
    window.addEventListener("storage", handleThemeChange);

    const observer = new MutationObserver(handleThemeChange);
    observer.observe(document.body, { attributes: true, attributeFilter: ['class'] });

    return () => {
      window.removeEventListener("storage", handleThemeChange);
      observer.disconnect();
    };
  }, []);

  const isDark = document.body.classList.contains("dark-mode");

  /* ================= HANDLERS ================= */
  const handleFileChange = (e) => {
    const file = e.target.files[0];
    setImage(file);
    if (file) {
      setPreview(URL.createObjectURL(file));
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');

    const fd = new FormData();
    fd.append('title', title);
    fd.append('body', body);
    if (image) fd.append('image', image);

    try {
      const { data } = await API.post('/posts', fd);
      navigate(`/posts/${data._id}`);
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to publish post');
    }
  };

  /* ================= STYLES ================= */
  const styles = {
    page: {
      minHeight: '100vh',
      display: 'flex',
      justifyContent: 'center',
      alignItems: 'center',
      padding: '40px 20px',
      backgroundColor: isDark ? '#560032' : '#FAE8ED',
      fontFamily: 'Georgia, serif',
      color: isDark ? '#f5f5f5' : 'rgb(12, 75, 52)',
      transition: 'all 0.3s ease',
    },
    container: {
      width: '100%',
      maxWidth: '800px',
      padding: '40px',
      borderRadius: '25px',
      backgroundColor: isDark ? '#2e091e' : '#f7c6d9',
      boxShadow: isDark ? '0 15px 40px rgba(0,0,0,0.5)' : '0 15px 40px rgba(0,0,0,0.1)',
    },
    heading: {
      textAlign: 'center',
      fontSize: '32px',
      fontWeight: 'bold',
      marginBottom: '30px',
    },
    form: {
      display: 'flex',
      flexDirection: 'column',
      gap: '20px'
    },
    label: {
      display: 'block',
      marginBottom: '8px',
      marginLeft: '15px',
      fontSize: '14px',
      fontWeight: 'bold',
      opacity: 0.8,
    },
    input: {
      padding: '16px 25px',
      borderRadius: '50px', // Pill shape
      border: '2px solid transparent',
      fontSize: '16px',
      outline: 'none',
      transition: '0.3s',
      fontFamily: 'Georgia, serif',
      backgroundColor: isDark ? '#3d1028' : '#fff',
      color: isDark ? '#fff' : 'rgb(12, 75, 52)',
      boxSizing: 'border-box',
    },
    textarea: {
      padding: '20px 25px',
      borderRadius: '25px', // Rounded corners
      border: '2px solid transparent',
      fontSize: '16px',
      outline: 'none',
      resize: 'none',
      minHeight: '250px',
      transition: '0.3s',
      fontFamily: 'Georgia, serif',
      backgroundColor: isDark ? '#3d1028' : '#fff',
      color: isDark ? '#fff' : 'rgb(12, 75, 52)',
      boxSizing: 'border-box',
    },
    focusBorder: {
      borderColor: isDark ? '#eca8b5' : 'rgb(12, 75, 52)',
    },
    button: {
      padding: '16px',
      borderRadius: '50px',
      border: 'none',
      fontWeight: 'bold',
      fontSize: '18px',
      cursor: 'pointer',
      backgroundColor: isDark ? '#eca8b5' : 'rgb(12, 75, 52)',
      color: isDark ? '#560032' : '#f7c6d9',
      transition: '0.3s',
      marginTop: '10px',
    },
    previewImg: {
      width: '100%',
      maxHeight: '300px',
      objectFit: 'cover',
      borderRadius: '15px',
      marginBottom: '15px',
      border: `2px solid ${isDark ? '#eca8b5' : 'rgb(12, 75, 52)'}`
    }
  };

  const getButtonStyle = () => {
    const base = styles.button;
    if (btnActive) return { ...base, transform: 'scale(0.97)' };
    if (btnHover) return { ...base, backgroundColor: '#ff7aa2', color: '#fff', transform: 'scale(1.02)' };
    return base;
  };

  return (
    <div style={styles.page}>
      <div style={styles.container}>
        <h2 style={styles.heading}>Compose Masterpiece</h2>

        {error && <p style={{ color: '#ff4d4d', textAlign: 'center', marginBottom: '15px' }}>{error}</p>}

        <form style={styles.form} onSubmit={handleSubmit}>
          <div>
            <label style={styles.label}>Post Title</label>
            <input
              value={title}
              onChange={(e) => setTitle(e.target.value)}
              placeholder="Give your story a name..."
              required
              style={{ ...styles.input, ...(titleFocus ? styles.focusBorder : {}), width: '100%' }}
              onFocus={() => setTitleFocus(true)}
              onBlur={() => setTitleFocus(false)}
            />
          </div>

          <div>
            <label style={styles.label}>Content</label>
            <textarea
              value={body}
              onChange={(e) => setBody(e.target.value)}
              placeholder="Once upon a time..."
              required
              style={{ ...styles.textarea, ...(bodyFocus ? styles.focusBorder : {}), width: '100%' }}
              onFocus={() => setBodyFocus(true)}
              onBlur={() => setBodyFocus(false)}
            />
          </div>

          {user?.role === 'admin' && (
            <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
              <label style={styles.label}>Featured Image (Admin only)</label>
              
              {preview && <img src={preview} alt="Preview" style={styles.previewImg} />}

              <input
                type="file"
                accept="image/*"
                id="fileUpload"
                style={{ display: 'none' }}
                onChange={handleFileChange}
              />

              <label
                htmlFor="fileUpload"
                style={{
                  ...styles.input,
                  textAlign: 'center',
                  cursor: 'pointer',
                  border: `2px dashed ${isDark ? '#eca8b5' : 'rgb(12, 75, 52)'}`,
                  opacity: 0.9
                }}
              >
                {image ? `📸 ${image.name}` : 'Click to Upload Cover Image'}
              </label>
            </div>
          )}

          <button
            type="submit"
            style={getButtonStyle()}
            onMouseEnter={() => setBtnHover(true)}
            onMouseLeave={() => setBtnHover(false)}
            onMouseDown={() => setBtnActive(true)}
            onMouseUp={() => setBtnActive(false)}
          >
            Publish Post
          </button>
        </form>
      </div>
    </div>
  );
};

export default CreatePostPage;
